mapper.update:
UPDATE bluenote_im.im_user_message
SET received_status = 1,
    updated_at = #{updatedAt}
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}
  AND conversation_seq <= #{conversationSeq}
  AND received_status = 0

UPDATE bluenote_im.im_user_message
SET read_status = 1,
    received_status = 1,
    updated_at = #{updatedAt}
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}
  AND conversation_seq <= #{conversationSeq}
  AND read_status = 0

